```plantuml
@startuml
class User {
    -id: integer
    -name: string
    +getId(): integer
    +getName(): string
}

class Employee {
    -position: string
    +getPosition(): string
}

class Owner {
    -balance: integer
    +getBalance(): integer
}

class CakeStore {
    -storeName: string
    -owner: Owner
    -employees: []Employee
}

class CoffeeStore {
    -storeName: string
    -owner: Owner
    -employees: []Employee
}

interface StoreInterface {
    +getStoreName(): string
    +getOwnerName(): string
    +getEmployees(): []Employee
}

class MainStore {
    +storeInterface: StoreInterface
}

User <|-- Employee
User <|-- Owner
CakeStore *-- Owner
CakeStore o-- Employee
CoffeeStore *-- Owner
CoffeeStore o-- Employee
CakeStore ..|> StoreInterface
CoffeeStore ..|> StoreInterface
MainStore --> StoreInterface

skinparam classAttributeIconSize 0
hide circle
@enduml
```
